import React, { useState } from "react";
import ClubHeader from "./ClubHeader";
import ClubMain from "./Clubs/ClubMain";

export default function ClubDetail() {
    const match = window.location.hash.match(/^#\/clubs\/(\d+)(?:\/(\w+))?/);
    const clubId = match ? Number(match[1]) : null;
    const activeTab = match?.[2] || "overview";

    const [club, setClub] = useState(null);

    if (!clubId) {
        return <div style={{ padding: 20 }}>Invalid club</div>;
    }

    return (
        <>
            {/* Header renders ONLY when club exists */}
            {club && (
                <ClubHeader
                    club={club}
                    activeTab={activeTab}
                />
            )}

            <ClubMain
                clubId={clubId}
                activeTab={activeTab}
                onClubLoaded={setClub}
            />
        </>
    );
}
